import org.apache.commons.text.StringEscapeUtils;

public class XSSFixedCode {

    public static void main(String[] args) {
        // Simulating user input as a malicious script
        String userInput = "<script>alert('XSS Attack!')</script>";

        // Properly sanitizing user input using HTML escaping
        String sanitizedInput = StringEscapeUtils.escapeHtml4(userInput);

        // Outputting sanitized user input within a div tag
        String output = "<div>" + sanitizedInput + "</div>";

        System.out.println(output);
    }
}

